// Message protocol
sealed trait AccountMessage
case class Deposit(amount: BigDecimal) extends AccountMessage
case class Withdraw(amount: BigDecimal) extends AccountMessage
case object GetBalance extends AccountMessage

// Response messages
sealed trait AccountResponse
case class BalanceUpdated(newBalance: BigDecimal) extends AccountResponse
case class WithdrawalFailed(reason: String, currentBalance: BigDecimal) extends AccountResponse
case class BalanceResponse(balance: BigDecimal) extends AccountResponse
case class DepositFailed(reason: String) extends AccountResponse

/**
 * Account balance manager actor.
 *
 * NOTE: Using `var balance` here is perfectly safe and idiomatic in Akka.
 * Akka actors process ONE message at a time — the actor's mailbox serializes
 * all incoming messages, so there are no concurrent reads/writes to `balance`.
 * No synchronization (locks, AtomicReference, etc.) is needed because the
 * actor model itself provides the concurrency guarantee.
 *
 * This is NOT the same as using an unprotected `var` in a multi-threaded
 * context — the Akka dispatcher and mailbox mechanism ensure happens-before
 * relationships between message processing steps.
 */
class AccountActor(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends Actor {

  // Safe to use var here: Akka guarantees single-threaded message processing per actor instance.
  // The Akka memory model ensures visibility of state changes across messages.
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= 0) {
        sender() ! DepositFailed(s"Invalid deposit amount: $amount. Must be positive.")
      } else {
        balance += amount
        sender() ! BalanceUpdated(balance)
      }

    case Withdraw(amount) =>
      if (amount <= 0) {
        sender() ! WithdrawalFailed(s"Invalid withdrawal amount: $amount. Must be positive.", balance)
      } else if (amount > balance) {
        sender() ! WithdrawalFailed(
          s"Insufficient funds. Requested: $amount, Available: $balance",
          balance
        )
      } else {
        balance -= amount
        sender() ! BalanceUpdated(balance)
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}

object AccountActor {
  def props(accountId: String, initialBalance: BigDecimal = BigDecimal(0)): Props =
    Props(new AccountActor(accountId, initialBalance))
}

/**
 * Account manager that routes messages to per-account actors.
 * This allows high throughput across different accounts while maintaining
 * consistency within each account.
 */
class AccountManagerActor extends Actor {

  private var accounts: Map[String, ActorRef] = Map.empty

  override def receive: Receive = {
    case (accountId: String, msg: AccountMessage) =>
      val accountActor = accounts.getOrElse(accountId, {
        val ref = context.actorOf(AccountActor.props(accountId), s"account-$accountId")
        accounts += (accountId -> ref)
        ref
      })
      accountActor.forward(msg)

    case CreateAccount(accountId, initialBalance) =>
      if (accounts.contains(accountId)) {
        sender() ! AccountCreationFailed(s"Account $accountId already exists")
      } else {
        val ref = context.actorOf(AccountActor.props(accountId, initialBalance), s"account-$accountId")
        accounts += (accountId -> ref)
        sender() ! AccountCreated(accountId)
      }
  }
}

case class CreateAccount(accountId: String, initialBalance: BigDecimal = BigDecimal(0))
case class AccountCreated(accountId: String)
case class AccountCreationFailed(reason: String)

object AccountManagerActor {
  def props: Props = Props(new AccountManagerActor)
}

